import type { TimelineSection } from '@lib/animations/section-timeline';

type CreateStubSection = (id: string) => TimelineSection;

export function getElements(id: string) {
  const section = document.getElementById(id);
  if (!section) throw new Error(`Section ${id} not found`);
  return { section };
}

export const createStubSection: CreateStubSection = id => {
  const elements = getElements(id);
  return {
    id: 'section-2',
    section: elements.section,
    animations: []
  };
};
