import type { AnimationLibs } from '@lib/animations/animation-libs';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { createCountUpAnimation, createSequentialThresholdAnimations } from '@lib/animations/text-animations';
import { interpolate } from '@utils/animations';

export type Section2Deps = {};

export function getElements(libs: AnimationLibs) {
  const section = document.getElementById('section2');
  const header = document.getElementById('section2Header');
  const title = document.getElementById('section2Title');
  const description = document.getElementById('section2Description');
  if (!section) throw new Error('Section 2 not found');
  if (!header) throw new Error('Header 2 not found');
  if (!title) throw new Error('Title 2 not found');
  if (!description) throw new Error('Description 2 not found');
  return {
    section,
    header,
    title,
    titleSplit: libs.SplitText.create(title, { type: 'words,chars', aria: 'none' }),
    description,
    descriptionSplit: libs.SplitText.create(description, { type: 'lines', aria: 'none' }),
    button: document.getElementById('section2Button')
  };
}

export const createSection2: CreateTimelineSection<Section2Deps> = libs => {
  const elements = getElements(libs);
  const animateText = createSequentialThresholdAnimations(libs, [
    { elements: elements.titleSplit.chars },
    { elements: elements.descriptionSplit.lines, startY: 0.04, overlap: 0.25, stagger: 0.1 }
  ]);
  const animateStat1 = createCountUpAnimation('stat1', libs);
  const animateStat2 = createCountUpAnimation('stat2', libs);
  const animateStat3 = createCountUpAnimation('stat3', libs);
  const animateStat4 = createCountUpAnimation('stat4', libs);
  if (!animateStat1 || !animateStat2 || !animateStat3 || !animateStat4)
    throw new Error('Failed to create stat animations.');
  return {
    id: 'section-2',
    section: elements.section,
    animations: [
      {
        id: 'fade-in-header',
        start: 10,
        end: 20,
        update: animateText
      },
      {
        id: 'count-up-stats',
        start: 30,
        end: 40,
        update: progress => {
          animateStat1(progress);
          animateStat2(progress);
          animateStat3(progress);
          animateStat4(progress);
        }
      },
      {
        id: 'fade-in-stats',
        start: 30,
        end: 50,
        update: progress => {
          const stats = libs.gsap.utils.toArray('.stat');
          const vh = window.innerHeight;
          libs.gsap.set(stats, {
            opacity: progress,
            y: vh * 0.1 * (1 - progress),
            scale: interpolate(0.8, 1, progress)
          });
        }
      }
    ]
  };
};
