import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { interpolate } from '@utils/animations';

export type Section4Deps = {};

// Custom easing function to simulate back.out(1.4)
function backOut(progress: number, overshoot = 1.4): number {
  const c1 = overshoot;
  const c3 = c1 + 1;
  return 1 + c3 * (progress - 1) ** 3 + c1 * (progress - 1) ** 2;
}

function getElements() {
  const section = document.getElementById('section4');
  const sigmaSection = document.querySelector('[data-sigma-features]') as HTMLElement | null;
  const sigmaLogoIcon = document.querySelector('.sigmaLogoIcon') as HTMLElement | null;
  const sigmaLogoText = document.querySelector('.sigmaLogoText') as HTMLElement | null;
  const sigmaTitle = document.querySelector('.sigmaTitle') as HTMLElement | null;
  const sigmaCards = document.querySelectorAll('.sigmaCard') as NodeListOf<HTMLElement>;

  // Card 1 elements (diagram)
  const card1DiagramNodes = document.querySelectorAll('.sigmaCard1 .diagramNode') as NodeListOf<HTMLElement>;
  const card1SvgLines = document.querySelectorAll('.sigmaCard1 .diagramSvgLine') as NodeListOf<SVGElement>;
  const card1LineElements = document.querySelectorAll('.sigmaCard1 .diagramSvgLine line') as NodeListOf<SVGLineElement>;
  // Card 2 elements (messages only, no diagram nodes)
  const card2Messages = document.querySelectorAll('.sigmaMessage') as NodeListOf<HTMLElement>;
  const card2MessageLine = document.querySelector('.sigmaMessageLine') as HTMLElement | null;

  // Card titles and descriptions
  const cardTitles = document.querySelectorAll('.sigmaCardTitle') as NodeListOf<HTMLElement>;
  const cardDescriptions = document.querySelectorAll('.sigmaCardDescription') as NodeListOf<HTMLElement>;

  if (!section) throw new Error('Section 4 not found');
  if (!sigmaSection) throw new Error('Sigma section not found');

  return {
    section,
    sigmaSection,
    sigmaLogoIcon,
    sigmaLogoText,
    sigmaTitle,
    sigmaCards,
    card1DiagramNodes,
    card1SvgLines,
    card1LineElements,
    card2Messages,
    card2MessageLine,
    cardTitles,
    cardDescriptions
  };
}

export const createSection4: CreateTimelineSection<Section4Deps> = libs => {
  const elements = getElements();
  const { gsap, SplitText } = libs;
  const vh = window.innerHeight;

  // Split text elements for character animations
  let titleSplit: { chars: Element[] } | null = null;
  const cardTitleSplits: { chars: Element[] }[] = [];
  const cardDescriptions = Array.from(elements.cardDescriptions);

  // Initialize splits
  if (elements.sigmaLogoText) {
    gsap.set(elements.sigmaLogoText, {
      opacity: 0,
      y: vh * 0.03,
      filter: 'blur(20px)'
    });
  }

  if (elements.sigmaTitle) {
    titleSplit = SplitText.create(elements.sigmaTitle, { type: 'words,chars' });
    gsap.set(elements.sigmaTitle, { opacity: 1 });
    gsap.set(titleSplit.chars, { opacity: 0, filter: 'blur(20px)' });
  }

  elements.cardTitles.forEach(title => {
    const split = SplitText.create(title, { type: 'words,chars' });
    cardTitleSplits.push(split);
    gsap.set(split.chars, { opacity: 0, filter: 'blur(20px)' });
  });

  gsap.set(cardDescriptions, { opacity: 0, y: 10 });

  // Set initial states for other elements
  if (elements.sigmaLogoIcon) {
    gsap.set(elements.sigmaLogoIcon, { opacity: 0, x: -20 });
  }

  gsap.set(elements.sigmaCards, { opacity: 0, y: 50, scale: 0.95 });
  gsap.set(elements.card1DiagramNodes, { opacity: 0, scale: 0.8 });
  gsap.set(elements.card1SvgLines, { opacity: 0 });
  elements.card1LineElements.forEach(line => {
    const length = line.getTotalLength?.() || 25;
    gsap.set(line, { strokeDasharray: length, strokeDashoffset: length });
  });

  gsap.set(elements.card2Messages, { opacity: 0, y: -20 });
  if (elements.card2MessageLine) {
    gsap.set(elements.card2MessageLine, { scaleY: 0, transformOrigin: 'top' });
  }

  // Track animation states
  let hasAnimatedLogoText = false;
  let hasAnimatedTitle = false;
  let hasAnimatedCardTitles = false;
  let hasAnimatedCardDescriptions = false;

  return {
    id: 'section-4',
    section: elements.section,
    animations: [
      // Logo icon slide + fade (0-10%)
      {
        id: 'logo-icon-fade',
        start: 0,
        end: 10,
        update: progress => {
          if (elements.sigmaLogoIcon) {
            gsap.set(elements.sigmaLogoIcon, {
              opacity: progress,
              x: interpolate(-20, 0, progress)
            });
          }
        }
      },
      // Logo text character blur reveal (5-20%)
      {
        id: 'logo-text-blur',
        start: 0,
        end: 10,
        update: progress => {
          if (elements.sigmaLogoText && !hasAnimatedLogoText && progress > 0.1) {
            gsap.to(elements.sigmaLogoText, {
              opacity: 1,
              y: 0,
              filter: 'blur(0px)',
              duration: 0.5,
              ease: 'power2.out'
            });
            hasAnimatedLogoText = true;
          } else if (progress < 0.05 && hasAnimatedLogoText) {
            gsap.set(elements.sigmaLogoText, {
              opacity: 0,
              y: vh * 0.03,
              filter: 'blur(20px)'
            });
            hasAnimatedLogoText = false;
          }
        }
      },
      // Title character blur reveal (10-30%)
      {
        id: 'title-blur',
        start: 5,
        end: 15,
        update: progress => {
          if (titleSplit && !hasAnimatedTitle && progress > 0.1) {
            gsap.to(titleSplit.chars, {
              opacity: 1,
              filter: 'blur(0px)',
              duration: 0.6,
              stagger: 0.03,
              ease: 'power2.out'
            });
            hasAnimatedTitle = true;
          } else if (progress < 0.05 && hasAnimatedTitle) {
            gsap.set(titleSplit?.chars || [], { opacity: 0, filter: 'blur(20px)' });
            hasAnimatedTitle = false;
          }
        }
      },
      // Cards scale + fade (15-35%)
      {
        id: 'cards-fade',
        start: 10,
        end: 20,
        update: progress => {
          gsap.set(elements.sigmaCards, {
            opacity: progress,
            y: vh * 0.05 * (1 - progress),
            scale: interpolate(0.95, 1, progress)
          });
        }
      },
      // Card 1 diagram nodes (25-50%)
      {
        id: 'card1-diagram-nodes',
        start: 30,
        end: 40,
        update: progress => {
          const nodesArray = Array.from(elements.card1DiagramNodes);
          nodesArray.forEach((node, i) => {
            const nodeProgress = Math.max(0, Math.min(1, (progress * nodesArray.length - i) / 1.5));
            const scale = interpolate(0.8, 1, backOut(nodeProgress));
            gsap.set(node, {
              opacity: nodeProgress,
              scale
            });
          });
        }
      },
      // Card 1 SVG lines draw (30-55%)
      {
        id: 'card1-svg-lines',
        start: 30,
        end: 40,
        update: progress => {
          elements.card1SvgLines.forEach(svg => {
            gsap.set(svg, { opacity: progress > 0.1 ? 1 : 0 });
          });
          const lineStagger = 0.14;
          elements.card1LineElements.forEach((line, i) => {
            const lineStart = i * lineStagger;
            const lineDuration = Math.max(0.001, 1 - lineStart);
            const lineProgress = Math.max(0, Math.min(1, (progress - lineStart) / lineDuration));
            const length = line.getTotalLength?.() || 25;
            if (lineProgress >= 1) {
              gsap.set(line, {
                strokeDasharray: '2 2',
                strokeDashoffset: 0
              });
            } else {
              gsap.set(line, {
                strokeDasharray: length,
                strokeDashoffset: length * (1 - lineProgress)
              });
            }
          });
        }
      },
      // Card 2 messages slide + fade (35-60%)
      {
        id: 'card2-messages',
        start: 30,
        end: 40,
        update: progress => {
          const messagesArray = Array.from(elements.card2Messages);
          messagesArray.forEach((msg, i) => {
            const msgProgress = Math.max(0, Math.min(1, progress * 2 - i * 0.3));
            gsap.set(msg, {
              opacity: msgProgress,
              y: interpolate(-20, 0, msgProgress)
            });
          });
        }
      },
      // Card 2 message line scaleY (40-60%)
      {
        id: 'card2-message-line',
        start: 30,
        end: 40,
        update: progress => {
          if (elements.card2MessageLine) {
            gsap.set(elements.card2MessageLine, { scaleY: progress });
          }
        }
      },
      // Card titles blur reveal (50-70%)
      {
        id: 'card-titles-blur',
        start: 35,
        end: 45,
        update: progress => {
          if (!hasAnimatedCardTitles && progress > 0.1) {
            cardTitleSplits.forEach(split => {
              gsap.to(split.chars, {
                opacity: 1,
                filter: 'blur(0px)',
                duration: 0.4,
                stagger: 0.02,
                ease: 'power2.out'
              });
            });
            hasAnimatedCardTitles = true;
          } else if (progress < 0.05 && hasAnimatedCardTitles) {
            cardTitleSplits.forEach(split => {
              gsap.set(split.chars, { opacity: 0, filter: 'blur(20px)' });
            });
            hasAnimatedCardTitles = false;
          }
        }
      },
      // Card descriptions line slide (55-75%)
      {
        id: 'card-descriptions-slide',
        start: 40,
        end: 50,
        update: progress => {
          if (!hasAnimatedCardDescriptions && progress > 0.1) {
            cardDescriptions.forEach((description, index) => {
              gsap.to(description, {
                opacity: 1,
                y: 0,
                duration: 0.4,
                delay: index * 0.08,
                ease: 'power2.out'
              });
            });
            hasAnimatedCardDescriptions = true;
          } else if (progress < 0.05 && hasAnimatedCardDescriptions) {
            gsap.set(cardDescriptions, { opacity: 0, y: 10 });
            hasAnimatedCardDescriptions = false;
          }
        }
      }
    ],
    dispose: () => {
      // Cleanup split text instances if needed
    }
  };
};
