import type { AnimationLibs } from '@lib/animations/animation-libs';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';
import { createSequentialThresholdAnimations } from '@lib/animations/text-animations';
import { interpolate } from '@utils/animations';

export type Section3Deps = {};

export function getElements(libs: AnimationLibs) {
  const section = document.getElementById('section3');
  const header = document.getElementById('section3Header');
  const title = document.getElementById('section3Title');
  const description = document.getElementById('section3Description');
  if (!section) throw new Error('Section 3 not found');
  if (!header) throw new Error('Header 3 not found');
  if (!title) throw new Error('Title 3 not found');
  if (!description) throw new Error('Description 3 not found');
  return {
    section,
    header,
    title,
    titleSplit: libs.SplitText.create(title, { type: 'words,chars', aria: 'none' }),
    description,
    descriptionSplit: libs.SplitText.create(description, { type: 'lines', aria: 'none' })
  };
}

// Track animation state for each card
type CardAnimationState = {
  hasAnimated: boolean;
  splitText?: { chars?: Element[]; lines?: Element[] };
};

const cardStates: Record<string, CardAnimationState> = {
  card1: { hasAnimated: false },
  card2: { hasAnimated: false },
  card3: { hasAnimated: false },
  card4: { hasAnimated: false },
  card5: { hasAnimated: false }
};

// Bento Card 1: Title, deal card, invest button, floating avatars
function createBentoCard1Animation(libs: AnimationLibs) {
  const card = document.querySelector('[data-bento-card-1]');
  if (!card) return null;

  const title = card.querySelector('.bentoCard1Title');
  const dealCard = card.querySelector('.dealCard');
  const investButton = card.querySelector('.investButton');
  const floatingAvatars = card.querySelectorAll('.floatingAvatar');

  if (!title) return null;

  // Create SplitText once
  const split = libs.SplitText.create(title, { type: 'words,chars' });
  libs.gsap.set(split.chars, { opacity: 0, y: 20 });

  return (progress: number) => {
    if (progress >= 1 && !cardStates.card1.hasAnimated) {
      // Animate title
      libs.gsap.set(title, { opacity: 1 });
      libs.gsap.to(split.chars, {
        opacity: 1,
        y: 0,
        duration: 0.6,
        stagger: 0.03,
        ease: 'power2.out'
      });

      // Animate deal card
      if (dealCard) {
        libs.gsap.set(dealCard, { scale: 0.95, y: 0 });
        libs.gsap.to(dealCard, {
          opacity: 1,
          scale: 1,
          y: 0,
          duration: 0.6,
          delay: 0.2,
          ease: 'power2.out'
        });
      }

      // Animate invest button
      if (investButton) {
        libs.gsap.set(investButton, { scale: 0.8, y: 10 });
        libs.gsap.to(investButton, {
          opacity: 1,
          scale: 1,
          y: 0,
          duration: 0.5,
          delay: 0.4,
          ease: 'back.out(1.4)'
        });
      }

      // Animate floating avatars
      if (floatingAvatars.length > 0) {
        libs.gsap.set(floatingAvatars, { scale: 0.6 });
        libs.gsap.to(floatingAvatars, {
          opacity: 1,
          scale: 1,
          duration: 0.5,
          delay: 0.6,
          stagger: { each: 0.12, from: 'random' },
          ease: 'back.out(1.7)'
        });
      }

      cardStates.card1.hasAnimated = true;
    } else if (progress < 0.1 && cardStates.card1.hasAnimated) {
      // Reset state
      libs.gsap.set(title, { opacity: 0 });
      libs.gsap.set(split.chars, { opacity: 0, y: 20 });
      if (dealCard) libs.gsap.set(dealCard, { opacity: 0, scale: 0.95, y: 0 });
      if (investButton) libs.gsap.set(investButton, { opacity: 0, scale: 0.8, y: 10 });
      if (floatingAvatars.length > 0) libs.gsap.set(floatingAvatars, { opacity: 0, scale: 0.6 });
      cardStates.card1.hasAnimated = false;
    }
  };
}

// Bento Card 2: Title "24/7", subtitle, message cards
function createBentoCard2Animation(libs: AnimationLibs) {
  const card = document.querySelector('[data-bento-card-2]');
  if (!card) return null;

  const title = card.querySelector('.bentoCard2Title');
  const subtitle = card.querySelector('.bentoCard2Subtitle');
  const messageCards = card.querySelectorAll('.messageCard');

  if (!title) return null;

  // Create SplitText once
  const split = libs.SplitText.create(title, { type: 'chars' });
  libs.gsap.set(split.chars, { opacity: 0, y: 30 });

  return (progress: number) => {
    if (progress >= 1 && !cardStates.card2.hasAnimated) {
      // Animate title
      libs.gsap.set(title, { opacity: 1 });
      libs.gsap.to(split.chars, {
        opacity: 1,
        y: 0,
        duration: 0.5,
        stagger: 0.08,
        ease: 'power2.out'
      });

      // Animate subtitle
      if (subtitle) {
        libs.gsap.to(subtitle, {
          opacity: 1,
          duration: 0.4,
          delay: 0.3,
          ease: 'power2.out'
        });
      }

      // Animate message cards
      if (messageCards.length > 0) {
        libs.gsap.set(messageCards, { y: 20 });
        libs.gsap.to(messageCards, {
          opacity: 1,
          y: 0,
          duration: 0.5,
          delay: 0.4,
          stagger: 0.15,
          ease: 'power2.out',
          onComplete: () => {
            messageCards.forEach(c => {
              (c as HTMLElement).style.transform = '';
            });
          }
        });
      }

      cardStates.card2.hasAnimated = true;
    } else if (progress < 0.1 && cardStates.card2.hasAnimated) {
      // Reset state
      libs.gsap.set(title, { opacity: 0 });
      libs.gsap.set(split.chars, { opacity: 0, y: 30 });
      if (subtitle) libs.gsap.set(subtitle, { opacity: 0 });
      if (messageCards.length > 0) libs.gsap.set(messageCards, { opacity: 0, y: 20 });
      cardStates.card2.hasAnimated = false;
    }
  };
}

