// Bento Card 4: Title, bar graph, line, dot
function createBentoCard4Animation(libs: AnimationLibs) {
  const card = document.querySelector('.bentoCard4');
  if (!card) return null;

  const cardId = card.id || 'bento-card-4';
  const title = document.getElementById(`${cardId}-title`);
  const line = document.getElementById(`${cardId}-line`);
  const dot = document.getElementById(`${cardId}-dot`);
  const barsContainer = document.getElementById(`${cardId}-bars`);
  const bars = barsContainer?.querySelectorAll('.bentoCard4Bar');

  if (!title || !line || !dot || !bars) return null;

  const linePath = line.querySelector('line');

  // Create SplitText once
  const split = libs.SplitText.create(title, { type: 'lines' });
  libs.gsap.set(split.lines, { opacity: 0, y: 20 });

  return (progress: number) => {
    if (progress >= 1 && !cardStates.card4.hasAnimated) {
      // Animate title
      libs.gsap.set(title, { opacity: 1 });
      libs.gsap.to(split.lines, {
        opacity: 1,
        y: 0,
        duration: 0.6,
        stagger: 0.15,
        ease: 'power2.out'
      });

      // Animate bars
      libs.gsap.to(bars, {
        scaleY: 1,
        duration: 0.5,
        delay: 0.3,
        stagger: 0.05,
        ease: 'power2.out'
      });

      // Animate line
      libs.gsap.set(line, { opacity: 1 });
      if (linePath) {
        libs.gsap.to(linePath, {
          strokeDashoffset: 0,
          duration: 0.4,
          delay: 0.5,
          ease: 'power2.inOut'
        });
      }

      // Animate dot
      libs.gsap.to(dot, {
        scale: 1,
        duration: 0.3,
        delay: 0.7,
        ease: 'back.out(1.7)'
      });

      cardStates.card4.hasAnimated = true;
    } else if (progress < 0.1 && cardStates.card4.hasAnimated) {
      // Reset state
      libs.gsap.set(title, { opacity: 0 });
      libs.gsap.set(split.lines, { opacity: 0, y: 20 });
      libs.gsap.set(bars, { scaleY: 0 });
      libs.gsap.set(line, { opacity: 0 });
      if (linePath) libs.gsap.set(linePath, { strokeDashoffset: 48 });
      libs.gsap.set(dot, { scale: 0 });
      cardStates.card4.hasAnimated = false;
    }
  };
}

