export const createSection3: CreateTimelineSection<Section3Deps> = libs => {
  const elements = getElements(libs);
  const animateCard1 = createBentoCard1Animation(libs);
  const animateCard2 = createBentoCard2Animation(libs);
  const animateCard3 = createBentoCard3Animation(libs);
  const animateCard4 = createBentoCard4Animation(libs);
  const animateCard5 = createBentoCard5Animation(libs);
  const animateText = createSequentialThresholdAnimations(libs, [
    { elements: elements.titleSplit.chars },
    { elements: elements.descriptionSplit.lines, startY: 0.04, overlap: 0.25, stagger: 0.1 }
  ]);

  // Mobile detection for faster animation timing
  const isMobile = window.matchMedia('(max-width: 768px)').matches;

  // Animation timing: faster on mobile (10-22% with 3% stagger) vs desktop (20-40% with 5% stagger)
  const cardTiming = isMobile
    ? { start: 10, stagger: 3, duration: 10 } // Mobile: starts at 10%, 3% between cards
    : { start: 20, stagger: 5, duration: 10 }; // Desktop: starts at 20%, 5% between cards

  return {
    id: 'section-3',
    section: elements.section,
    animations: [
      {
        id: 'fade-in-header',
        start: 10,
        end: 20,
        update: animateText
      },
      {
        id: 'fade-in-bento-cards',
        start: 10,
        end: 20,
        update: progress => {
          const cards = libs.gsap.utils.toArray('.bentoCard');
          libs.gsap.set(cards, {
            opacity: progress,
            scale: interpolate(0.95, 1, progress)
          });
        }
      },
      // Bento card internal animations - staggered timing (faster on mobile)
      {
        id: 'bento-card-1-entrance',
        start: cardTiming.start,
        end: cardTiming.start + cardTiming.duration,
        update: progress => animateCard1?.(progress)
      },
      {
        id: 'bento-card-2-entrance',
        start: cardTiming.start + cardTiming.stagger,
        end: cardTiming.start + cardTiming.stagger + cardTiming.duration,
        update: progress => animateCard2?.(progress)
      },
      {
        id: 'bento-card-3-entrance',
        start: cardTiming.start + cardTiming.stagger * 2,
        end: cardTiming.start + cardTiming.stagger * 2 + cardTiming.duration,
        update: progress => animateCard3?.(progress)
      },
      {
        id: 'bento-card-4-entrance',
        start: cardTiming.start + cardTiming.stagger * 3,
        end: cardTiming.start + cardTiming.stagger * 3 + cardTiming.duration,
        update: progress => animateCard4?.(progress)
      },
      {
        id: 'bento-card-5-entrance',
        start: cardTiming.start + cardTiming.stagger * 4,
        end: cardTiming.start + cardTiming.stagger * 4 + cardTiming.duration,
        update: progress => animateCard5?.(progress)
      }
    ]
  };
};
