import type { AnimationLibs } from '@lib/animations/animation-libs';
import type { CreateTimelineSection } from '@lib/animations/section-timeline';

export type Section1Deps = {};

function getElements(libs: AnimationLibs) {
  const section = document.getElementById('section1');
  const header = document.getElementById('section1Header');
  const title = document.getElementById('section1Title');
  const description = document.getElementById('section1Description');
  const label = document.getElementById('section1Label');
  const perks = document.getElementById('section1Perks');
  if (!section) throw new Error('Section 1 not found');
  if (!header) throw new Error('Header 1 not found');
  if (!title) throw new Error('Title 1 not found');
  if (!description) throw new Error('Description 1 not found');
  if (!label) throw new Error('Label 1 not found');
  if (!perks) throw new Error('Perks 1 not found');
  return {
    section,
    header,
    title,
    titleSplit: libs.SplitText.create(title, { type: 'words,chars' }),
    description,
    label,
    perks
  };
}

export function fadeInHeader1(libs: AnimationLibs) {
  const elements = getElements(libs);
  const vh = window.innerHeight;
  libs.gsap.to(elements.header, { opacity: 1 });
  libs.gsap.set(elements.title, { opacity: 1 });
  libs.gsap.set(elements.titleSplit.chars, { opacity: 0, filter: 'blur(8px)' });

  // animateCharacters(libs, elements.title, { duration: 0.8 });
  libs.gsap.to(elements.titleSplit.chars, {
    opacity: 1,
    filter: 'blur(0px)',
    duration: 0.5,
    ease: 'power2.out',
    stagger: 0.05
  });
  libs.gsap.fromTo(
    elements.description,
    { opacity: 0, y: vh * 0.1 },
    {
      opacity: 0.7,
      y: 0,
      duration: 1.2,
      delay: 0.5,
      ease: 'power2.out'
    }
  );
  libs.gsap.to(elements.label, { opacity: 1, duration: 1.2, delay: 0.75 });
  libs.gsap.fromTo(
    elements.perks,
    { opacity: 0, y: '4vh' },
    { opacity: 1, y: 0, duration: 0.8, delay: 1.2, ease: 'power2.out' }
  );
}

export const createSection1: CreateTimelineSection<Section1Deps> = libs => {
  const elements = getElements(libs);
  return {
    id: 'section-1',
    section: elements.section,
    start: 'top',
    animations: []
  };
};
